_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = (vUv-.5);// * uAspect.xy;

vec2 uv6 = uv1;
float z = q28*4*length((abs(uv1.x)-abs(uv1.y)));
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-2,2);
uv1 -= rs/40;

uv6 = .4*cos(uv1*4+uTime);
mus = .005/(length(uv6));

vec3 crisp= texture(sampler_main,(uv1)*(.95-q28/16+.4*z)+.5);

vec3 ret1 = crisp + mus;

ret = (ret1*.99-.03);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvo = vUv*uAspect.xy;
vUv = multiply(vUv*uAspect.xy,mat2(_qa));
vUv = vUv + -.0- .2*vec2(q5,q6);
vec2 uv1 = (vUv-.5 );//*uAspect.xy;

//Kugel1
rsk = (uv1 + vec2 (q9,q10)) ;
dz1 = normalize(rsk);
rad1 = q11*length(rsk) ;
uv4 =  tan(rad1)*dz1;
mask1 = clamp01(8-8*rad1);
Kugel1 = uv4*mask1*8/q11;
uv1 += Kugel1*.1;

//Kugel2
rsk = (sin(q27*atan(uv1.x,uv1.y)/2)) ;
dz2 = normalize(rsk);
rad2 = 1*length(rsk) ;
uv4 =  tan(rad2)*dz2;
mask2 = clamp01(8-8*rad2);
Kugel2 = uv4*mask2;

//Kugel3
float argu = length(uv1+q5*uv1.y);
rsk = (sin(.1*(q27-8)/ argu));
//rsk = (sin(.5*q27*atan(uv1.x,uv1.y))) ;
dz3 = normalize(rsk);
rad3 = 1*length(rsk) ;
uv4 =  tan(-rad3)*dz3;
mask3 = clamp01(8-8*rad3);
Kugel3 = uv4*mask3;

vec2 dz = (Kugel1 + q12*Kugel2*length(uv1) + q13*Kugel3*argu);
//******************** STARS
rss0.x = atan(uv1.x, uv1.y)/3.1416;
rss0.y = .01/(length(uv1));

rss = vec2 (rss0.x,rss0.y+uTime/2)+dz;
rss = multiply(rss,mat2(.7,.7,-.7,.7));
float noise = (texture(sampler_pw_noise_lq,rss/32)-.8 >= 0);
tmp = abs(fract(rss*8)-.5);

//*************************
uv1 -= dz*.5;
float z = .2/(length(uv1)+q21);
uv2.y = z + q8;
uv2.x = rss0.x +q7;
uv3 =fract(uv2);
cathed =  texture(sampler_main,uv3+.4*dz)*12;

float mod = (q22+1)/6;

//Deckenbeleuchtung:
fire = clamp01(.05*q22/length(uv1)*
 (lum(texture(sampler_main,uv3+.0)))) ;

//Tasaechl. Feuer; Problem: uv1 passt nicht zu uv3
fire += clamp01(.02*q22/length(uv1)*
 (lum(texture(sampler_main,uv1+.5))))/length(uv1);

k1 = lum(fire);
fire = k1*vec3(1,k1*.8,k1*k1/3)  ;

uvo+=dz;
sky = clamp01(.02/length(uvo-.3)) * 1;

vec3 dots = clamp01(.04/length(tmp)) *noise;
dots *= clamp01(.2/abs(rss0.y));
dots = clamp01(lum(dots)*lum(dots)*1);
k1 = lum(dots);
dots= k1*vec3(1,k1*.8,k1*k1/3) *2 ;
float cmask = clamp01(1-16*lum(GetBlur1(fract(uv3))));
ret += sky * cmask;
ret += fire+dots;

ret += sky*cathed/2;
float dis = length(uv1);
float crot = sin((dis+uTime)*12);
vec3 blk = mod * vec3 (crot,1-crot,2-dis)*dis;
blk *= (q12*(1/rad2+q15*mask2)+q13*(1/rad3+q15*mask3))/2 ;
blk += q22/rad1*roam_cos-mask1/4 ;
ret += blk;


  fragColor = ret;
}
